import React, { useState, useEffect } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

export default function Dashboard() {
  const [vista, setVista] = useState("productos");

  // --- Estados para Productos ---
  const [productos, setProductos] = useState([]);
  const [nuevoProducto, setNuevoProducto] = useState({
    ProductoID: "",
    Nombre: "",
    Precio: "",
    Stock: "",
  });
  const [editandoProducto, setEditandoProducto] = useState(false);

  // --- Estados para Categorías ---
  const [categorias, setCategorias] = useState([]);
  const [nuevaCategoria, setNuevaCategoria] = useState({
    id: "",
    nombre: "",
    descripcion: "",
  });
  const [editandoCategoria, setEditandoCategoria] = useState(false);

  // --- URLs ---
  const API_PRODUCTOS = "http://localhost:5000/api/productos";
  const API_CATEGORIAS = "http://localhost:5000/api/categorias";

  // ==============================================================
  // 🔹 PRODUCTOS
  const obtenerProductos = async () => {
    try {
      const res = await axios.get(API_PRODUCTOS);
      setProductos(res.data);
    } catch (error) {
      console.error("Error al obtener productos:", error);
    }
  };

  const handleChangeProducto = (e) => {
    setNuevoProducto({ ...nuevoProducto, [e.target.name]: e.target.value });
  };

  const handleSubmitProducto = async (e) => {
    e.preventDefault();
    try {
      if (editandoProducto) {
        await axios.put(`${API_PRODUCTOS}/${nuevoProducto.ProductoID}`, nuevoProducto);
        setEditandoProducto(false);
      } else {
        await axios.post(API_PRODUCTOS, nuevoProducto);
      }

      setNuevoProducto({ ProductoID: "", Nombre: "", Precio: "", Stock: "" });
      obtenerProductos();
    } catch (error) {
      console.error("Error al guardar producto:", error);
    }
  };

  const editarProducto = (producto) => {
    setNuevoProducto(producto);
    setEditandoProducto(true);
  };

  const eliminarProducto = async (ProductoID) => {
    try {
      await axios.delete(`${API_PRODUCTOS}/${ProductoID}`);
      obtenerProductos();
    } catch (error) {
      console.error("Error al eliminar producto:", error);
    }
  };

  // ==============================================================
  // 🔹 CATEGORÍAS
  const obtenerCategorias = async () => {
    try {
      const res = await axios.get(API_CATEGORIAS);
      setCategorias(res.data);
    } catch (error) {
      console.error("Error al obtener categorías:", error);
    }
  };

  const handleChangeCategoria = (e) => {
    setNuevaCategoria({ ...nuevaCategoria, [e.target.name]: e.target.value });
  };

  const handleSubmitCategoria = async (e) => {
    e.preventDefault();
    try {
      if (editandoCategoria) {
        await axios.put(`${API_CATEGORIAS}/${nuevaCategoria.id}`, nuevaCategoria);
        setEditandoCategoria(false);
      } else {
        await axios.post(API_CATEGORIAS, nuevaCategoria);
      }

      setNuevaCategoria({ id: "", nombre: "", descripcion: "" });
      obtenerCategorias();
    } catch (error) {
      console.error("Error al guardar categoría:", error);
    }
  };

  const editarCategoria = (categoria) => {
    setNuevaCategoria(categoria);
    setEditandoCategoria(true);
  };

  const eliminarCategoria = async (id) => {
    try {
      await axios.delete(`${API_CATEGORIAS}/${id}`);
      obtenerCategorias();
    } catch (error) {
      console.error("Error al eliminar categoría:", error);
    }
  };

  // ==============================================================
  useEffect(() => {
    if (vista === "productos") obtenerProductos();
    else obtenerCategorias();
  }, [vista]);

  // ==============================================================
  return (
    <div className="container mt-5">
      {/* Pestañas */}
      <ul className="nav nav-tabs mb-4">
        <li className="nav-item">
          <button
            className={`nav-link ${vista === "productos" ? "active" : ""}`}
            onClick={() => setVista("productos")}
          >
            🛒 Productos
          </button>
        </li>
        <li className="nav-item">
          <button
            className={`nav-link ${vista === "categorias" ? "active" : ""}`}
            onClick={() => setVista("categorias")}
          >
            🗂️ Categorías
          </button>
        </li>
      </ul>

      {/* ===================================================== */}
      {/* VISTA DE PRODUCTOS */}
      {vista === "productos" && (
        <>
          <div className="card shadow-lg border-0 rounded-4 mb-5">
            <div className="card-header bg-primary text-white text-center py-3">
              <h2>{editandoProducto ? "Editar Producto" : "Agregar Producto"}</h2>
            </div>

            <div className="card-body">
              <form onSubmit={handleSubmitProducto} className="row g-3">
                <div className="col-md-4">
                  <label className="form-label">Nombre</label>
                  <input
                    type="text"
                    name="Nombre"
                    value={nuevoProducto.Nombre}
                    onChange={handleChangeProducto}
                    className="form-control"
                    required
                  />
                </div>

                <div className="col-md-4">
                  <label className="form-label">Precio</label>
                  <input
                    type="number"
                    name="Precio"
                    value={nuevoProducto.Precio}
                    onChange={handleChangeProducto}
                    className="form-control"
                    required
                  />
                </div>

                <div className="col-md-4">
                  <label className="form-label">Stock</label>
                  <input
                    type="number"
                    name="Stock"
                    value={nuevoProducto.Stock}
                    onChange={handleChangeProducto}
                    className="form-control"
                    required
                  />
                </div>

                <div className="col-12 text-center mt-3">
                  <button
                    type="submit"
                    className={`btn ${editandoProducto ? "btn-warning" : "btn-success"} px-5`}
                  >
                    {editandoProducto ? "Actualizar" : "Agregar"}
                  </button>
                </div>
              </form>
            </div>
          </div>

          {/* Tabla de productos */}
          <div className="card shadow-sm border-0 rounded-4">
            <div className="card-header bg-dark text-white text-center py-3">
              <h3>Lista de Productos</h3>
            </div>

            <div className="card-body">
              {productos.length === 0 ? (
                <p className="text-center text-muted">No hay productos registrados.</p>
              ) : (
                <div className="table-responsive">
                  <table className="table table-striped table-hover align-middle text-center">
                    <thead className="table-primary">
                      <tr>
                        <th>ID</th>
                        <th>Nombre</th>
                        <th>Precio</th>
                        <th>Stock</th>
                        <th>Acciones</th>
                      </tr>
                    </thead>
                    <tbody>
                      {productos.map((p) => (
                        <tr key={p.ProductoID}>
                          <td>{p.ProductoID}</td>
                          <td>{p.Nombre}</td>
                          <td>${p.Precio}</td>
                          <td>{p.Stock}</td>
                          <td>
                            <button
                              className="btn btn-warning btn-sm me-2"
                              onClick={() => editarProducto(p)}
                            >
                              Editar
                            </button>
                            <button
                              className="btn btn-danger btn-sm"
                              onClick={() => eliminarProducto(p.ProductoID)}
                            >
                              Eliminar
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </>
      )}

      {/* ===================================================== */}
      {/* VISTA DE CATEGORÍAS */}
      {vista === "categorias" && (
        <>
          <div className="card shadow-lg border-0 rounded-4 mb-5">
            <div className="card-header bg-success text-white text-center py-3">
              <h2>{editandoCategoria ? "Editar Categoría" : "Agregar Categoría"}</h2>
            </div>

            <div className="card-body">
              <form onSubmit={handleSubmitCategoria} className="row g-3">
                <div className="col-md-6">
                  <label className="form-label">Nombre</label>
                  <input
                    type="text"
                    name="nombre"
                    value={nuevaCategoria.nombre}
                    onChange={handleChangeCategoria}
                    className="form-control"
                    required
                  />
                </div>

                <div className="col-md-6">
                  <label className="form-label">Descripción</label>
                  <input
                    type="text"
                    name="descripcion"
                    value={nuevaCategoria.descripcion}
                    onChange={handleChangeCategoria}
                    className="form-control"
                  />
                </div>

                <div className="col-12 text-center mt-3">
                  <button
                    type="submit"
                    className={`btn ${editandoCategoria ? "btn-warning" : "btn-primary"} px-5`}
                  >
                    {editandoCategoria ? "Actualizar" : "Agregar"}
                  </button>
                </div>
              </form>
            </div>
          </div>

          {/* Tabla de categorías */}
          <div className="card shadow-sm border-0 rounded-4">
            <div className="card-header bg-dark text-white text-center py-3">
              <h3>Lista de Categorías</h3>
            </div>

            <div className="card-body">
              {categorias.length === 0 ? (
                <p className="text-center text-muted">No hay categorías registradas.</p>
              ) : (
                <div className="table-responsive">
                  <table className="table table-striped table-hover align-middle text-center">
                    <thead className="table-success">
                      <tr>
                        <th>ID</th>
                        <th>Nombre</th>
                        <th>Descripción</th>
                        <th>Acciones</th>
                      </tr>
                    </thead>
                    <tbody>
                      {categorias.map((c) => (
                        <tr key={c.id}>
                          <td>{c.id}</td>
                          <td>{c.nombre}</td>
                          <td>{c.descripcion}</td>
                          <td>
                            <button
                              className="btn btn-warning btn-sm me-2"
                              onClick={() => editarCategoria(c)}
                            >
                              Editar
                            </button>
                            <button
                              className="btn btn-danger btn-sm"
                              onClick={() => eliminarCategoria(c.id)}
                            >
                              Eliminar
                            </button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        </>
      )}
    </div>
  );
}
